import time
import functools

def retry_with_exponential_backoff(retries=3, backoff_factor=0.5):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for i in range(retries + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if i == retries:
                        raise

                    delay = backoff_factor * (2 ** i)
                    time.sleep(delay)
        return wrapper
    return decorator
